// mm/src/api/listDocuments.js
import axios from 'axios';
import { withAuthRetry } from './refresh';

const API_BASE =
  process.env.REACT_APP_API_BASE_URL || 'https://manuscriptmagic.fowkes.xyz/services';

const ACCESS_KEY = 'mm_accessToken';

function getAccessToken() {
  return localStorage.getItem(ACCESS_KEY) || '';
}

/**
 * List all documents for the authenticated user
 *
 * Endpoint: listDocuments.php
 * requires: accessToken
 * returns: { success, message, documents[] }
 */
export const listDocuments = async () => {
  const accessToken = getAccessToken();

  // DEV MOCK (no backend configured)
  if (!process.env.REACT_APP_API_BASE_URL) {
    return new Promise((resolve) => {
      setTimeout(() => {
        resolve({
          data: {
            success: true,
            message: 'Mock listDocuments success',
            documents: [
              {
                documentId: 'mock_doc_1001',
                filename: 'MyBook.docx',
                filePath: '/mock/docs/MyBook.docx',
                uploadedAt: new Date().toISOString(),
              },
              {
                documentId: 'mock_doc_1002',
                filename: 'Cover.png',
                filePath: '/mock/docs/Cover.png',
                uploadedAt: new Date().toISOString(),
              },
            ],
          },
        });
      }, 300);
    });
  }

  const url = `${API_BASE}/listDocument.php`;

  return withAuthRetry(() =>
    axios.get(url, {
      headers: {
        'Content-Type': 'application/json',
        Authorization: `Bearer ${accessToken}`,
      },
    })
  );
};
